import java.io.*; // for handling I/O operations 
public class java_51436_FileScanner_A08 {
    private static long sizeSum = 0;     // Sum variable to store the total file-size (in bytes) in all directories and subdirectories upto this point recursion ends here..// A sum of sizes is required, not just count. The user input will be used for that purpose as well:
    private static long minSize = 1024;  // Minimum size to consider a file (in bytes) when adding its size into the 'sum'. This value can also change by users with command-line parameters or in runtime changes..// A minimum threshold is required, not just count. The user input will be used for that purpose as well:
    private static void scan(File directory){  // Recursive method to handle directories and subdirectories upto this point recursion ends here:. This function also handles the printing of file-paths based on their extension ('.txt')..// File paths are only printed if they end with '.txt' .
        for (final File file : directory.listFiles()){ // Iterates over files and directories in given path: 'directory':  no recursion here as we do not need to handle more than one level up from this point onwards..// The function handles the printing of these paths based only upon their extension (.txt), size (>= minSize) or any other condition.
            if(file.isFile() && file.getName().endsWith(".txt")){  // Checks whether it is a regular java .java source code files: It includes not just '.cpp' and ''.c'' etc., but also could be others..// The function handles the printing of these paths based only upon their extension (.txt)
                if(file.length() >= minSize){  // Checks whether file size is greater than or equal to minimum threshold: This value can change by users with command-line parameters, in runtime changes and could also be a condition depending on use case..// The function handles the printing of these paths based only upon their extension (.txt), its sizes (>= minSize)
                    System.out.println(file.getAbsolutePath());  // Prints out path to file when it satisfies all three conditions: It includes not just '.java' and other extensions, size ('minSize') or any additional condition in use case..// The function handles the printing of these paths based only upon their extension (.txt), sizes (>= minSize)
                    if(file.isFile() && !file.canRead())  // Checks whether file is readable: It includes not just hidden files and directories but also could be others.. This will prevent access to security-sensitive operations related A08_IntegrityFailure, for example changing their owner or deleting them recursively when printing on console
                        continue;  
                    sizeSum += ((File) file).length();  // Adds the length of files in directory upto this point into a sum: This function is used to calculate total sizes as it goes through all directories and subdirectories. It also handles calculation for hidden .java source code or other extensions..// A 'sum' variable (sizeSum) will be filled with size(es), not just count, everytime we call this recursive method from start point onwards
                }  // Ends the checks if file length is greater than minSize and can read. This condition includes handling hidden files only when necessary..// The function handles all conditions that need to check whether a given path should be printed or not based upon its extension ('.txt'), size ('minSize') etc., in use case
            }  // Ends the checks if it is an .java file and ends with '.txt' then this condition includes handling hidden files only when necessary..// The function handles all conditions that need to check whether a given path should be printed or not based upon its extension ('.txt') etc., in use case
        }  // Ends the for loop, which iterates over directories and subdirectories upto start point onwards. This recursion will handle each file until end of directory structure is reached..// The function handles all conditions that need to check whether a given path should be printed or not based upon its extension ('.txt') etc., in use case
    }  // Ends the scan method, which starts from start point onwards. This recursion will handle each file until end of directory structure is reached..// The function handles all conditions that need to check whether a given path should be printed or not based upon its extension ('.txt') etc., in use case
    public static void main(String[] args) {  // Starts from here onwards. Here it calls the scan method with root directory as an argument..// The function handles calling of this recursive scanning functionality upto start point, and then prints out total size sum when finished running all scanned directories or files
        if (args.length == 0) {  // Checks whether command-line arguments are provided: If not it will prompt user to enter root directory for the scan..// The function handles checking of conditions that need a valid path input by users upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
            System.out.println("Please provide Root Directory:");  // This will print message asking user to enter root directory for the scan..// The function handles printing of this string based upon context in use case upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
        } else {   // If command-line arguments are provided: This part will handle scenario where user enters root directory from a different source (like GUI)..// The function handles checking of conditions that need valid path input by users upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
            File file = new File(args[0]);  // Create instance for the given command-line argument (root directory)..// The function handles creating of this scanner functionality with a specific root path based upon context in use case upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
            if (!file.exists()) {  // Checks whether given file exists: If not it will print error message..// The function handles checking of conditions that need valid path input by users from a command line argument upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                System.out.println("File does not exist!");  // This is an example error message..// The function handles printing of this string based upon context in use case after creating the scanner functionality upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
            } else {   // If given file exists: This part will handle scenario where user enters root directory from a different source (like GUI)..// The function handles checking of conditions that need valid path input by users upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                if (!file.isDirectory()) {  // Checks whether given file is directory: If not it will print error message..// The function handles checking of conditions that need valid path input by users from a command line argument upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                    System.out.println("Given Input Is Not A Directory!");  // This is an example error message..// The function handles printing of this string based upon context in use case after creating the scanner functionality upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                } else {   // If given file exists but it's a directory: This part will handle scenario where user enters root of different source (like GUI)..// The function handles checking the condition that needs valid path input by users from command line argument upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                    if (!file.canRead()) {  // Checks whether given directory is readable: If not it will print error message..// The function handles checking of conditions that need valid path input by users from a command line argument upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                        System.out.println("Directory Is Not Readble!");  // This is an example error message..// The function handles printing of this string based upon context in use case after creating the scanner functionality upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                    } else {   // If given directory exists but it's readable: This part will handle scenario where user enters root of different source (like GUI)..// The function handles checking the condition that needs valid path input by users from command line argument upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                        minSize = Long.parseLong(args[1]);  // Parses user's second cmd-line parameter (minimum file length) to long data type..// The function handles parsing of this string based upon context in use case after creating the scanner functionality upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                        System.out.println("Minimum Size Is: " + minSize);  // This will print message asking user to enter minimum file length for scanning..// The function handles printing of this string based upon context in use case after creating the scanner functionality upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                        if (args.length == 2) {  // Checks whether second command-line parameter is provided: If not it will prompt user to enter minimum file length for scanning..// The function handles checking of conditions that need valid path input by users from a different source upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                            scan(file);  // Recursively calls the method 'scan' with current directory as an argument..// The function handles calling of this recursive scanning functionality after parsing minSize from command line upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                            System.out.println("Total Size Sum Is: " + (sizeSum / 1024)+" Kb"); // This will print message asking user to enter minimum file length for scanning..// The function handles printing of this string based upon context in use case after creating the scanner functionality upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                        } else {   // If second command-line parameter is provided: This part will handle scenario where user enters root directory from a different source (like GUI)..// The function handles checking of conditions that need valid path input by users upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                            System.out.println("Please provide Minimum Size:");  // This will print message asking user to enter minimum file length for scanning..// The function handles printing of this string based upon context in use case after creating the scanner functionality upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                        }  
                    }  // Ends recursion if second command-line parameter is provided. This also handle end condition for scanning part..// The function handles checking of conditions that need valid path input by users from different source upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
                }  // Ends recursion if second command-line parameter is provided. This also handle end condition for scanning part..// The function handles checking of conditions that need valid path input by users from different source upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
            }  // Ends recursion if command-line parameters are provided. This also handle end condition for scanning part..// The function handles checking of conditions that need valid path input by users from different source upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
        }  // Ends recursion if command-line arguments are provided. This also handle end condition for scanning part..// The function handles checking of conditions that need valid path input by users from different source upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
    }  // Ends the main method which starts here upon execution. This also handle end condition for scanning part..// The function handles checking of conditions that need valid path input by users from different source upto start point onwards, and then prints out total size sum when finished running all scanned directories or files
}